import { NavLink } from "react-router-dom";
import { useState } from "react"; // ✅ needed for collapse state
import { hasRole } from "../utils/auth";

export default function Sidebar() {

  // ✅ get current user from localStorage
  const user = JSON.parse(localStorage.getItem("user"));

  // ✅ controls whether sidebar is collapsed or not
  // true  = small (icons only)
  // false = expanded (icons + text)
  const [collapsed, setCollapsed] = useState(true);

  // ✅ logout function
  const handleLogout = () => {
    localStorage.removeItem("user"); // remove login session
    window.location.href = "/"; // redirect to login page
  };

  // ✅ class for active menu styling
  const navClass = ({ isActive }) =>
    isActive
      ? "sidebar-link active-link"
      : "sidebar-link";

  return (

    <div
      // ✅ THIS IS THE IMPORTANT PART
      // if collapsed = true → adds "collapsed" class
      // if collapsed = false → removes it
      className={`bg-success text-white p-3 vh-100 sidebar ${
        collapsed ? "collapsed" : ""
      }`}

      // ✅ when mouse enters → expand sidebar
      onMouseEnter={() => setCollapsed(false)}

      // ✅ when mouse leaves → collapse sidebar
      onMouseLeave={() => setCollapsed(true)}
    >

      {/* ✅ TITLE */}
      <h4 className="mb-4">
        {/* hide text when collapsed */}
        <span className="menu-text">AGV Portal</span>
      </h4>

      <ul className="nav flex-column">

        {/* ✅ DASHBOARD */}
        <li className="nav-item">
          <NavLink to="/dashboard" className={navClass}>
  <i className="bi bi-speedometer2"></i>
  <span className="menu-text ms-2">Dashboard</span>
</NavLink>
        </li>

        {/* ✅ FLOOD */}
        <li className="nav-item">
          <NavLink to="/flood" className={navClass}>
  <i className="bi bi-water"></i>
  <span className="menu-text ms-2">Flood Monitoring</span>
</NavLink>
        </li>

        {/* ✅ USERS (only for admin roles) */}
        {hasRole(["super_admin", "it_admin"]) && (
          <li className="nav-item">
            <NavLink to="/users" className={navClass}>
              <i className="bi bi-people me-2"></i>
              <span className="menu-text">Users</span>
            </NavLink>
          </li>
        )}

        {/* ✅ COMPANIES (only super_admin) */}
        {hasRole(["super_admin"]) && (
          <li className="nav-item">
            <NavLink to="/companies" className={navClass}>
              <i className="bi bi-buildings me-2"></i>
              <span className="menu-text">Companies</span>
            </NavLink>
          </li>
        )}

      </ul>

      {/* ✅ SHOW USER NAME */}
      <p className="text-white text-center mt-4 mb-2">
        <span className="menu-text">{user?.name}</span>
      </p>

      {/* ✅ LOGOUT BUTTON */}
      <button
        className="btn btn-light w-100"
        onClick={handleLogout}
      >
        <i className="bi bi-box-arrow-right me-2"></i>
        <span className="menu-text">Logout</span>
      </button>

    </div>
  );
}
